// theme.service.ts - VERSIONE DEFINITIVA
import { Injectable, Inject, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { BehaviorSubject } from 'rxjs';

export type Theme = 'light' | 'dark';

@Injectable({
  providedIn: 'root'
})
export class ThemeService {
  private currentThemeSubject = new BehaviorSubject<Theme>('light');
  public currentTheme$ = this.currentThemeSubject.asObservable();

  constructor(@Inject(PLATFORM_ID) private platformId: any) {
  }

  // Inizializzazione esplicita
  initializeTheme(): void {
    if (isPlatformBrowser(this.platformId)) {
      const savedTheme = localStorage.getItem('app-theme') as Theme;
      const initialTheme = savedTheme || 'light';
      
      this.applyTheme(initialTheme);
      this.currentThemeSubject.next(initialTheme);
    }
  }

  setTheme(theme: Theme) {
    this.applyTheme(theme);
    this.currentThemeSubject.next(theme);
    
    if (isPlatformBrowser(this.platformId)) {
      localStorage.setItem('app-theme', theme);
    }
  }

  toggleTheme() {
    const newTheme = this.currentThemeSubject.value === 'light' ? 'dark' : 'light';
    this.setTheme(newTheme);
  }

  // 🔥 CORREZIONE: Metodo pubblico per applicare il tema
  public applyTheme(theme: Theme): void {
    if (isPlatformBrowser(this.platformId)) {
      const html = document.documentElement;
            
      // Rimuovi TUTTI gli attributi tema
      html.removeAttribute('data-theme');
      html.classList.remove('light-theme', 'dark-theme');
      
      // Applica il nuovo tema
      html.setAttribute('data-theme', theme);
      html.classList.add(theme + '-theme');
            
      // 🔥 FORZA il reflow per assicurarsi che il CSS venga applicato
      void html.offsetHeight;
    }
  }

  getCurrentTheme(): Theme {
    return this.currentThemeSubject.value;
  }
}